import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Cliente, MetricasPerfil } from '../models/cliente.model';
import { firstValueFrom } from 'rxjs';

@Injectable({
  providedIn: 'root',
})
export class ClienteService {
  private http = inject(HttpClient);
  private readonly API_URL = 'http://localhost:3000/api/clientes';
  private clienteCache = new Map<
    string,
    { datos: Cliente; tiempoFetch: number }
  >();
  private bundleSizeCache: number | null = null;

  private getBundleSize(): number {
    if (this.bundleSizeCache !== null) {
      return this.bundleSizeCache;
    }

    const resources = performance.getEntriesByType('resource');
    let totalSize = 0;

    for (const resource of resources) {
      const name = resource.name.toLowerCase();
      if (name.includes('.js')) {
        const perfResource = resource as PerformanceResourceTiming;
        totalSize += perfResource.transferSize || 0;
      }
    }

    this.bundleSizeCache = totalSize;
    return totalSize;
  }

  async buscarCliente(
    identificacion: string
  ): Promise<{ cliente: Cliente; metricas: MetricasPerfil }> {
    const metricas: MetricasPerfil = {
      scriptingTime: 0,
      transformacionDatos: 0,
      renderingPainting: 0,
      bundleSize: 0,
      cacheStatus: 'miss',
      tiempoCache: 0,
      tiempoNoCache: 0,
      timestamp: Date.now(),
    };

    const startScripting = performance.now();
    let tiempoFetchActual = 0;
    let clienteEncontrado: Cliente | null = null;

    if (this.clienteCache.has(identificacion)) {
      const cached = this.clienteCache.get(identificacion)!;
      clienteEncontrado = cached.datos;
      tiempoFetchActual = cached.tiempoFetch;
      metricas.cacheStatus = 'hit';
      metricas.tiempoCache = tiempoFetchActual;
    } else {
      const startFetch = performance.now();

      try {
        const response = await firstValueFrom(
          this.http.get<any>(`${this.API_URL}?identificacion=${identificacion}`)
        );
        const endFetch = performance.now();
        tiempoFetchActual = endFetch - startFetch;

        const startTransformacion = performance.now();
        const data = response;
        const endTransformacion = performance.now();

        metricas.transformacionDatos = endTransformacion - startTransformacion;
        metricas.cacheStatus = 'miss';
        metricas.tiempoNoCache = tiempoFetchActual;

        if (Array.isArray(data) && data.length > 0) {
          clienteEncontrado = data[0];
        } else if (data && typeof data === 'object') {
          clienteEncontrado = data;
        } else {
          throw new Error('Respuesta inesperada de la API');
        }

        if (clienteEncontrado) {
          this.clienteCache.set(identificacion, {
            datos: clienteEncontrado,
            tiempoFetch: tiempoFetchActual,
          });
        }
      } catch (error) {
        throw new Error('Error al consultar la API');
      }
    }

    if (!clienteEncontrado) {
      throw new Error('Cliente no encontrado');
    }

    metricas.scriptingTime = performance.now() - startScripting;
    metricas.bundleSize = this.getBundleSize();

    await new Promise((resolve) => setTimeout(resolve, 0));

    const observer = new PerformanceObserver((list) => {
      for (const entry of list.getEntries()) {
        if (
          entry.entryType === 'paint' ||
          entry.entryType === 'largest-contentful-paint'
        ) {
          metricas.renderingPainting = entry.duration || 0;
        }
      }
    });

    observer.observe({
      entryTypes: ['paint', 'largest-contentful-paint'],
      buffered: true,
    });

    await new Promise((resolve) => setTimeout(resolve, 50));
    observer.disconnect();

    return { cliente: clienteEncontrado, metricas };
  }

  limpiarCache(): void {
    this.clienteCache.clear();
  }
}
